import{_ as s,c as a,o as i,a1 as t}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Read Skill Files: Safely Access Skill Resources | opencode-agent-skills","description":"Learn to use read_skill_file tool. Access docs, configs, and examples in skill directories with built-in path security.","frontmatter":{"title":"Read Skill Files: Safely Access Skill Resources | opencode-agent-skills","sidebarTitle":"Read Files","subtitle":"Read Skill Files: Safely Access Skill Resources","description":"Learn to use read_skill_file tool. Access docs, configs, and examples in skill directories with built-in path security.","tags":["Skill Files","Tool Usage","Path Security"],"prerequisite":["start-installation","platforms-listing-available-skills"],"order":6},"headers":[],"relativePath":"joshuadavidthomas/opencode-agent-skills/platforms/reading-skill-files/index.md","filePath":"joshuadavidthomas/opencode-agent-skills/platforms/reading-skill-files/index.md"}'),l={name:"joshuadavidthomas/opencode-agent-skills/platforms/reading-skill-files/index.md"};function n(o,e,p,r,c,d){return i(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="read-skill-files" tabindex="-1">Read Skill Files <a class="header-anchor" href="#read-skill-files" aria-label="Permalink to &quot;Read Skill Files&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Use the <code>read_skill_file</code> tool to read documentation, configuration, and example files from skill directories</li><li>Understand the path security mechanism to prevent directory traversal attacks</li><li>Master XML format file content injection</li><li>Handle error messages and available file listings when files don&#39;t exist</li></ul><h2 id="your-current-challenge" tabindex="-1">Your Current Challenge <a class="header-anchor" href="#your-current-challenge" aria-label="Permalink to &quot;Your Current Challenge&quot;">​</a></h2><p>A skill&#39;s SKILL.md contains only core guidance, but many skills provide supporting files such as documentation, configuration examples, usage guides, and more. You want to access these files for more detailed instructions, but you don&#39;t know how to safely read files under skill directories.</p><h2 id="when-to-use-this" tabindex="-1">When to Use This <a class="header-anchor" href="#when-to-use-this" aria-label="Permalink to &quot;When to Use This&quot;">​</a></h2><ul><li><strong>View detailed documentation</strong>: Skills have detailed usage guides in their <code>docs/</code> directory</li><li><strong>Configuration examples</strong>: Need to reference example configuration files in the <code>config/</code> directory</li><li><strong>Code examples</strong>: Skills&#39; <code>examples/</code> directory contains code examples</li><li><strong>Debugging assistance</strong>: View the skill&#39;s README or other documentation files</li><li><strong>Understand resource structure</strong>: Explore what files are available in a skill directory</li></ul><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><p>The <code>read_skill_file</code> tool allows you to safely access support files under skill directories. It guarantees safety and usability through the following mechanisms:</p><div class="info custom-block"><p class="custom-block-title">Security Mechanism</p><p>The plugin strictly validates file paths to prevent directory traversal attacks:</p><ul><li>Forbidden from using <code>..</code> to access files outside the skill directory</li><li>Forbidden from using absolute paths</li><li>Only allows access to files within the skill directory and its subdirectories</li></ul></div><p>Tool execution flow:</p><ol><li>Verify that the skill name exists (supports namespaces)</li><li>Check if the requested file path is safe</li><li>Read file content</li><li>Wrap in XML format and inject into session context</li><li>Return success confirmation message</li></ol><div class="tip custom-block"><p class="custom-block-title">File Content Persistence</p><p>File content is injected via <code>synthetic: true</code> and <code>noReply: true</code> flags, which means:</p><ul><li>File content becomes part of the session context</li><li>Content remains accessible even after session compaction</li><li>Injection doesn&#39;t trigger an immediate AI response</li></ul></div><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-read-skill-documentation" tabindex="-1">Step 1: Read Skill Documentation <a class="header-anchor" href="#step-1-read-skill-documentation" aria-label="Permalink to &quot;Step 1: Read Skill Documentation&quot;">​</a></h3><p>Assume there&#39;s detailed usage documentation in the skill directory:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input:</span></span>
<span class="line"><span>Read the git-helper documentation</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System call:</span></span>
<span class="line"><span>read_skill_file(skill=&quot;git-helper&quot;, filename=&quot;docs/usage-guide.md&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System response:</span></span>
<span class="line"><span>File &quot;docs/usage-guide.md&quot; from skill &quot;git-helper&quot; loaded.</span></span></code></pre></div><p>File content will be injected into the session context in XML format:</p><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">skill-file</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> skill</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;git-helper&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> file</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;docs/usage-guide.md&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">metadata</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">directory</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;/path/to/project/.opencode/skills/git-helper&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">directory</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">metadata</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">content</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"># Git Helper Usage Guide</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">This skill provides guidance for Git branch management, commit conventions, and collaboration workflows...</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[Documentation content continues]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">content</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">skill-file</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p><strong>You should see</strong>: A success message, with file content injected into the session context.</p><h3 id="step-2-read-configuration-examples" tabindex="-1">Step 2: Read Configuration Examples <a class="header-anchor" href="#step-2-read-configuration-examples" aria-label="Permalink to &quot;Step 2: Read Configuration Examples&quot;">​</a></h3><p>View the skill&#39;s example configuration:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input:</span></span>
<span class="line"><span>Show docker-helper&#39;s configuration example</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System call:</span></span>
<span class="line"><span>read_skill_file(skill=&quot;docker-helper&quot;, filename=&quot;config/docker-compose.yml.example&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System response:</span></span>
<span class="line"><span>File &quot;config/docker-compose.yml.example&quot; from skill &quot;docker-helper&quot; loaded.</span></span></code></pre></div><p><strong>You should see</strong>: Configuration file content injected, and AI can reference the example to generate actual configuration for you.</p><h3 id="step-3-read-files-using-namespaces" tabindex="-1">Step 3: Read Files Using Namespaces <a class="header-anchor" href="#step-3-read-files-using-namespaces" aria-label="Permalink to &quot;Step 3: Read Files Using Namespaces&quot;">​</a></h3><p>If there are skills with the same name at both project and user levels:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input:</span></span>
<span class="line"><span>Read the build script from project:build-helper</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System call:</span></span>
<span class="line"><span>read_skill_file(skill=&quot;project:build-helper&quot;, filename=&quot;scripts/build.sh&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System response:</span></span>
<span class="line"><span>File &quot;scripts/build.sh&quot; from skill &quot;build-helper&quot; loaded.</span></span></code></pre></div><p><strong>You should see</strong>: The namespace clearly specifies the skill&#39;s source.</p><h3 id="step-4-handle-file-not-found" tabindex="-1">Step 4: Handle File Not Found <a class="header-anchor" href="#step-4-handle-file-not-found" aria-label="Permalink to &quot;Step 4: Handle File Not Found&quot;">​</a></h3><p>If you attempt to read a non-existent file:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input:</span></span>
<span class="line"><span>Read api-docs.md from git-helper</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System call:</span></span>
<span class="line"><span>read_skill_file(skill=&quot;git-helper&quot;, filename=&quot;api-docs.md&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System response:</span></span>
<span class="line"><span>File &quot;api-docs.md&quot; not found. Available files: docs/usage-guide.md, examples/branch-flow.md, README.md, SKILL.md</span></span></code></pre></div><p>The tool will list all available files in the skill directory, helping you find the correct filename.</p><p><strong>You should see</strong>: An error message and a list of available files.</p><h3 id="step-5-experience-path-security-protection" tabindex="-1">Step 5: Experience Path Security Protection <a class="header-anchor" href="#step-5-experience-path-security-protection" aria-label="Permalink to &quot;Step 5: Experience Path Security Protection&quot;">​</a></h3><p>Attempt to access files outside the skill directory:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input:</span></span>
<span class="line"><span>Read the parent directory file from git-helper</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System call:</span></span>
<span class="line"><span>read_skill_file(skill=&quot;git-helper&quot;, filename=&quot;../secrets.txt&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System response:</span></span>
<span class="line"><span>Invalid path: cannot access files outside skill directory.</span></span></code></pre></div><p>The tool will reject any request attempting to access files outside the skill directory.</p><p><strong>You should see</strong>: A path security error message.</p><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><ul><li>[ ] Can you use <code>read_skill_file</code> to read skill files?</li><li>[ ] Can you understand the purpose of the path security mechanism?</li><li>[ ] Can you identify the XML format of file content injection?</li><li>[ ] Can you find the list of available files from error messages?</li><li>[ ] Can you use namespaces to precisely locate skills?</li></ul><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><h3 id="pitfall-1-incorrect-file-path" tabindex="-1">Pitfall 1: Incorrect File Path <a class="header-anchor" href="#pitfall-1-incorrect-file-path" aria-label="Permalink to &quot;Pitfall 1: Incorrect File Path&quot;">​</a></h3><p>If you forget that the file is in a subdirectory:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input:</span></span>
<span class="line"><span>Read usage-guide.md from git-helper</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System response:</span></span>
<span class="line"><span>File &quot;usage-guide.md&quot; not found. Available files: docs/usage-guide.md, examples/branch-flow.md, README.md</span></span></code></pre></div><p><strong>Cause</strong>: The file might be in a subdirectory and requires a relative path.</p><p><strong>Solution</strong>: Use the full path, such as <code>docs/usage-guide.md</code>.</p><h3 id="pitfall-2-ignoring-namespace-conflicts" tabindex="-1">Pitfall 2: Ignoring Namespace Conflicts <a class="header-anchor" href="#pitfall-2-ignoring-namespace-conflicts" aria-label="Permalink to &quot;Pitfall 2: Ignoring Namespace Conflicts&quot;">​</a></h3><p>When skills with the same name exist in multiple namespaces:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input:</span></span>
<span class="line"><span>Read the README from build-helper</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System response:</span></span>
<span class="line"><span>File &quot;README.md&quot; from skill &quot;build-helper&quot; loaded.</span></span></code></pre></div><p>You might be reading a project-level skill, but expected a user-level skill.</p><p><strong>Solution</strong>: Use the namespace to explicitly specify, such as <code>read_skill_file(skill=&quot;user:build-helper&quot;, filename=&quot;README.md&quot;)</code>.</p><h3 id="pitfall-3-attempting-path-traversal" tabindex="-1">Pitfall 3: Attempting Path Traversal <a class="header-anchor" href="#pitfall-3-attempting-path-traversal" aria-label="Permalink to &quot;Pitfall 3: Attempting Path Traversal&quot;">​</a></h3><p>Try using <code>..</code> to access parent directories:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input:</span></span>
<span class="line"><span>Read a file outside the skill directory</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System call:</span></span>
<span class="line"><span>read_skill_file(skill=&quot;my-skill&quot;, filename=&quot;../../../etc/passwd&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System response:</span></span>
<span class="line"><span>Invalid path: cannot access files outside skill directory.</span></span></code></pre></div><p><strong>Cause</strong>: This is a security restriction to prevent directory traversal attacks.</p><p><strong>Solution</strong>: Only access files within the skill directory. For other files, have the AI use the <code>Read</code> tool directly.</p><h3 id="pitfall-4-file-already-exists-in-session-context" tabindex="-1">Pitfall 4: File Already Exists in Session Context <a class="header-anchor" href="#pitfall-4-file-already-exists-in-session-context" aria-label="Permalink to &quot;Pitfall 4: File Already Exists in Session Context&quot;">​</a></h3><p>If you&#39;ve already loaded a skill, file content might be in the skill&#39;s SKILL.md or other injected content:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input:</span></span>
<span class="line"><span>Read the skill&#39;s core documentation</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System call:</span></span>
<span class="line"><span>read_skill_file(skill=&quot;my-skill&quot;, filename=&quot;core-guide.md&quot;)</span></span></code></pre></div><p>But this might be unnecessary, as core content is usually in SKILL.md.</p><p><strong>Solution</strong>: First check the content of loaded skills to confirm if additional files are needed.</p><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>The <code>read_skill_file</code> tool allows you to safely access support files under skill directories:</p><ul><li><strong>Secure Path Checks</strong>: Prevents directory traversal, only allows access to files within the skill directory</li><li><strong>XML Injection Mechanism</strong>: File content is wrapped in <code>&lt;skill-file&gt;</code> XML tags with metadata</li><li><strong>User-Friendly Errors</strong>: When files don&#39;t exist, lists available files to help you find the correct path</li><li><strong>Namespace Support</strong>: Can use <code>namespace:skill-name</code> to precisely locate skills with the same name</li><li><strong>Context Persistence</strong>: Through the <code>synthetic: true</code> flag, file content remains accessible even after session compaction</li></ul><p>This tool is perfect for reading a skill&#39;s:</p><ul><li>Detailed documentation (<code>docs/</code> directory)</li><li>Configuration examples (<code>config/</code> directory)</li><li>Code examples (<code>examples/</code> directory)</li><li>README and documentation files</li><li>Script source code (if you need to view the implementation)</li></ul><h2 id="next-up" tabindex="-1">Next Up <a class="header-anchor" href="#next-up" aria-label="Permalink to &quot;Next Up&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../../advanced/claude-code-compatibility/">Claude Code Skill Compatibility</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>How the plugin is compatible with Claude Code&#39;s skill and plugin systems</li><li>Understand tool mapping mechanisms (converting Claude Code tools to OpenCode tools)</li><li>Master methods for discovering skills from Claude Code installation locations</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line</th></tr></thead><tbody><tr><td>ReadSkillFile tool definition</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L74-L135" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>74-135</td></tr><tr><td>Path security check</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L130-L133" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>130-133</td></tr><tr><td>List skill files</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L289-L316" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>289-316</td></tr><tr><td>resolveSkill function</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L269-L283" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>269-283</td></tr><tr><td>injectSyntheticContent function</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L147-L162" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>147-162</td></tr></tbody></table><p><strong>Key Types</strong>:</p><ul><li><code>Skill</code>: Skill metadata interface (<code>skills.ts:43-52</code>)</li><li><code>OpencodeClient</code>: OpenCode SDK client type (<code>utils.ts:140</code>)</li><li><code>SessionContext</code>: Session context containing model and agent information (<code>utils.ts:142-145</code>)</li></ul><p><strong>Key Functions</strong>:</p><ul><li><code>ReadSkillFile(directory: string, client: OpencodeClient)</code>: Returns tool definition, handles skill file reading</li><li><code>isPathSafe(basePath: string, requestedPath: string): boolean</code>: Validates whether a path is within the base directory, prevents directory traversal</li><li><code>listSkillFiles(skillPath: string, maxDepth: number = 3): Promise&lt;string[]&gt;</code>: Lists all files in the skill directory (excluding SKILL.md)</li><li><code>resolveSkill(skillName: string, skillsByName: Map&lt;string, Skill&gt;): Skill | null</code>: Supports <code>namespace:skill-name</code> format skill resolution</li><li><code>injectSyntheticContent(client, sessionID, text, context)</code>: Injects content into session via <code>noReply: true</code> and <code>synthetic: true</code></li></ul><p><strong>Business Rules</strong>:</p><ul><li>Path security check uses <code>path.resolve()</code> to verify, ensuring the resolved path starts with the base directory (<code>utils.ts:131-132</code>)</li><li>When file doesn&#39;t exist, attempts <code>fs.readdir()</code> to list available files, providing friendly error messages (<code>tools.ts:126-131</code>)</li><li>File content is wrapped in XML format with <code>skill</code>, <code>file</code> attributes and <code>&lt;metadata&gt;</code>, <code>&lt;content&gt;</code> tags (<code>tools.ts:111-119</code>)</li><li>When injecting, gets the current session&#39;s model and agent context to ensure content is injected into the correct context (<code>tools.ts:121-122</code>)</li></ul><p><strong>Security Mechanisms</strong>:</p><ul><li>Directory traversal protection: <code>isPathSafe()</code> checks if path is within base directory (<code>utils.ts:130-133</code>)</li><li>Provides fuzzy matching suggestions when skill doesn&#39;t exist (<code>tools.ts:90-95</code>)</li><li>Lists available files when file doesn&#39;t exist, helping users find the correct path (<code>tools.ts:126-131</code>)</li></ul></details>`,71)])])}const g=s(l,[["render",n]]);export{u as __pageData,g as default};
